12	const PROCESSING_FEE = 5;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const CAP_MULTIPLIER = 2;
33	
34	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
35	const BLOCK_SIZE = 3;
36	const BLOCK_PREMIUM = 60;
37	const CURSE_SURCHARGE_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const HIGH_ENCHANTMENT_THRESHOLD = 5;
40	const FIRST_INSURANCE_RATE = 0.1;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const LOYALTY_YEARS_THRESHOLD = 2;
43	const FOLLOWUP_DISCOUNT_RATE = 0.15;
44	const DEDUCTIBLE = 100;
45	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
46	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
47	
48	function itemSurcharge(item: Item): number {
49	  const itemBase = BASE_PREMIUMS[item.type];
50	  let surcharge = 0;
51	  if (item.cursed) surcharge += itemBase * CURSE_SURCHARGE_RATE;
52	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
53	    surcharge += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
54	  }
55	  return surcharge;
56	}
57	
58	function typeSubtotal(type: string, count: number): number {
59	  const isBlock = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
60	  return isBlock ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
61	}
62	
63	function loyaltyDiscount(customer: Customer, policyBase: number): number {
64	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
65	    ? policyBase * LOYALTY_DISCOUNT_RATE
66	    : 0;
67	}
68	
69	function followupDiscount(customer: Customer, policyBase: number): number {
70	  return customer.previousContracts >= 1
71	    ? policyBase * FOLLOWUP_DISCOUNT_RATE
72	    : 0;
73	}
74	
75	export type Damage = {
76	  itemType: string;
77	  amount: number;
78	};
79	
80	function reimbursementAmount(item: Item | undefined, damageAmount: number): number {
81	  const isHighEnchantment =
82	    !!item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
83	  return isHighEnchantment
84	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE * damageAmount
85	    : damageAmount;
86	}
87	
88	function countByKey<T>(values: T[], key: (value: T) => string): Record<string, number> {
89	  const counts: Record<string, number> = {};
90	  for (const value of values) {
91	    const k = key(value);
92	    counts[k] = (counts[k] ?? 0) + 1;
93	  }
94	  return counts;
95	}
96	
97	export function claim(
98	  items: Item[],
99	  damages: Damage[],
100	  previousPaid: number = 0,
101	): { payout: number; remainingCap: number } {
102	  const negative = damages.find((d) => d.amount < 0);
103	  if (negative) {
104	    throw new Error(`negative damage amount: ${negative.amount}`);
105	  }
106	  const itemCounts = countByKey(items, (i) => i.type);
107	  const damageCounts = countByKey(damages, (d) => d.itemType);
108	  for (const [type, count] of Object.entries(damageCounts)) {
109	    if (count > (itemCounts[type] ?? 0)) {
110	      throw new Error(`damage count exceeds insured count for type ${type}`);
111	    }
112	  }
113	  const totalPayout = damages.reduce((sum, damage) => {
114	    const item = items.find((i) => i.type === damage.itemType);
115	    const reimbursed = reimbursementAmount(item, damage.amount);
116	    return sum + Math.max(0, reimbursed - DEDUCTIBLE);
117	  }, 0);
118	  const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
119	  const cap = CAP_MULTIPLIER * insuranceSum;
120	  const capRemainingBeforeClaim = cap - previousPaid;
121	  const cappedPayout = Math.min(Math.floor(totalPayout), capRemainingBeforeClaim);
122	  return { payout: cappedPayout, remainingCap: capRemainingBeforeClaim - cappedPayout };
123	}
124	
125	export function quote(customer: Customer, items: Item[]): number {
126	  for (const item of items) {
127	    if (BASE_PREMIUMS[item.type] === undefined) {
128	      throw new Error(`unknown item type: ${item.type}`);
129	    }
130	  }
131	  const countsByType = countByKey(items, (i) => i.type);
132	
133	  const policyBase = Object.entries(countsByType)
134	    .reduce((sum, [type, count]) => sum + typeSubtotal(type, count), 0);
135	
136	  const itemSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
137	  const loyalty = loyaltyDiscount(customer, policyBase);
138	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
139	  const followup = followupDiscount(customer, policyBase);
140	
141	  return Math.ceil(policyBase + itemSurcharges - loyalty + firstInsurance - followup) + PROCESSING_FEE;
142	}
