export function runScenario(scenario: Scenario): { results: StepResult[] } {
  const results: StepResult[] = [];
  const policyItemsByStep: Record<number, Item[]> = {};
  const previousPaidByStep: Record<number, number> = {};

  scenario.steps.forEach((step, index) => {
    if (step.op === "quote") {
      const premium = quote(scenario.customer, step.items);
      policyItemsByStep[index] = step.items;
      previousPaidByStep[index] = 0;
      results.push({ premium });
    } else if (step.op === "claim") {
      const items = policyItemsByStep[step.policyStep] ?? [];
      const previousPaid = previousPaidByStep[step.policyStep] ?? 0;
      const result = claim(items, step.incident.damages, previousPaid);
      previousPaidByStep[step.policyStep] = previousPaid + result.payout;
      results.push({ payout: result.payout, remainingCap: result.remainingCap });
    }
  });

  return { results };
}

function main(): void {
  try {
    const input = readFileSync(0, "utf-8");
    const scenario = JSON.parse(input) as Scenario;
    const result = runScenario(scenario);
    process.stdout.write(JSON.stringify(result));
  } catch (err) {
    process.stderr.write(err instanceof Error ? err.message : String(err));
    process.exit(1);
  }
}

if (process.argv[1]?.endsWith("cli.ts") || process.argv[1]?.endsWith("cli.js")) {
  main();
}
